let itemsData={};let activeCategory=null;let edgeColSize=4;let edgeContainer=null;let _itemSearchTimeout=null;export function loadItems(path,container=document.getElementById("cards-container"),col=3){fetch(path).then(r=>r.json()).then(json=>{itemsData=json;edgeContainer=container;edgeColSize=Math.floor(12/col);buildCategoryMenu();setupGlobalItemSearch();const firstCat=Object.keys(itemsData)[0];if(firstCat){activeCategory=firstCat;renderCategory(firstCat);const defaultBtn=[...document.querySelectorAll("#sidebar .list-group-item")].find(btn=>btn.textContent===firstCat);if(defaultBtn)defaultBtn.classList.add("active");}}).catch(err=>console.error("JSON load error:",err));}
function buildCategoryMenu(){const sb=document.getElementById("sidebar");sb.innerHTML="";sb.insertAdjacentHTML("beforeend",`<label class="form-label">Categories :</label>`);const catList=document.createElement("div");catList.className="list-group";Object.keys(itemsData).forEach(cat=>{const btn=document.createElement("button");btn.className="list-group-item list-group-item-action";btn.textContent=cat;btn.addEventListener("click",()=>{activeCategory=cat;document.querySelectorAll("#sidebar .list-group-item").forEach(e=>e.classList.remove("active"));btn.classList.add("active");const searchEl=document.getElementById("items-search");if(searchEl)searchEl.value="";renderCategory(cat);});catList.appendChild(btn);});sb.appendChild(catList);}
function setupGlobalItemSearch(){const searchEl=document.getElementById("items-search");if(!searchEl)return;searchEl.addEventListener("input",e=>{clearTimeout(_itemSearchTimeout);const q=e.target.value.toLowerCase();_itemSearchTimeout=setTimeout(()=>{if(!q.trim()){if(activeCategory)renderCategory(activeCategory);}else{const results=globalItemSearch(q);if(results&&Object.keys(results).length>0){renderGlobalItemSearchResults(results);}else{const pane=edgeContainer;pane.innerHTML=`<div class="alert alert-info">No items match "<strong>${escapeHTML(q)}</strong>"</div>`;}}},200);});}
function globalItemSearch(query){if(!query)return null;const q=query.toLowerCase();const results={};Object.entries(itemsData).forEach(([category,catData])=>{if(!catData||typeof catData!=="object")return;Object.entries(catData).forEach(([subcategory,entries])=>{if(subcategory==="_display"||!Array.isArray(entries))return;const matches=[];entries.forEach(item=>{if(typeof item!=="object"||!item)return;const nameMatch=Object.values(item).some(v=>v&&String(v).toLowerCase().includes(q));if(nameMatch){matches.push(item);}});if(matches.length>0){if(!results[category])results[category]={};results[category][subcategory]=matches;}});});return Object.keys(results).length>0?results:null;}
function renderGlobalItemSearchResults(results){const pane=edgeContainer;pane.innerHTML="";pane.insertAdjacentHTML("afterbegin",`<h2 class="mb-1" style="font-size:1.5rem;">Search Results</h2>`);const row=document.createElement("div");row.className="row g-3 mt-2";pane.appendChild(row);Object.entries(results).forEach(([category,subcats])=>{Object.entries(subcats).forEach(([subcategory,items])=>{items.forEach(item=>{const wrapper=document.createElement("div");wrapper.className=`col-12 col-md-${edgeColSize} d-flex flex-column`;const contextBadge=document.createElement("div");contextBadge.className="mb-2";contextBadge.innerHTML=`
          <small class="text-muted">
            From <strong>${escapeHTML(category)}</strong>
            ${subcategory !== "Items" ? `› ${escapeHTML(subcategory)}` : ""}
          </small>
        `;wrapper.appendChild(contextBadge);const card=document.createElement("div");card.className="card flex-grow-1 bg-body border shadow-sm overflow-hidden rounded-3";const body=document.createElement("div");body.className="card-body bg-body-secondary";const name=getItemName(item);const source=itemSource(item,category);body.insertAdjacentHTML("beforeend",`<h5 class="card-title">${escapeHTML(name)} <span class="badge bg-secondary">${escapeHTML(subcategory)}</span> <span class="badge bg-info">${escapeHTML(source)}</span></h5>`);Object.entries(item).forEach(([k,v])=>{if(["Name","Source","source"].includes(k))return;let displayValue=String(v);if(k==="Price"&&!isNaN(v)){displayValue=`₽${v}`;}
body.insertAdjacentHTML("beforeend",`<p><strong>${escapeHTML(k)}:</strong> ${escapeHTML(displayValue)}</p>`);});card.appendChild(body);wrapper.appendChild(card);row.appendChild(wrapper);});});});}
function renderCategory(cat){const pane=edgeContainer;pane.innerHTML="";const queryInput=document.getElementById("items-search");const q=(queryInput&&queryInput.value||"").toLowerCase();const categoryData=itemsData[cat];if(!categoryData||typeof categoryData!=="object")return;const displayConfig=categoryData._display||{};Object.entries(categoryData).forEach(([subcat,entries])=>{if(subcat==="_display")return;if(Array.isArray(entries)){const section=document.createElement("section");section.className="mb-4";section.insertAdjacentHTML("beforeend",`<h3 class="mb-3 border-bottom pb-2" style="font-size:1.15rem;">${escapeHTML(subcat)}</h3>`);const row=document.createElement("div");row.className="row g-3";section.appendChild(row);pane.appendChild(section);const meta=normalizeDisplayMeta(displayConfig[subcat]);if(meta.type==="table"){renderAsTable(entries,subcat,meta,q,row);}else{renderAsCards(entries,subcat,q,row);}}});window.scrollTo({top:0,behavior:"smooth"});}
function normalizeDisplayMeta(raw){if(raw==="table")return{type:"table",rowPerField:true,idField:undefined,columns:undefined,columnLabels:undefined};if(typeof raw==="object"&&raw){return{type:raw.type==="table"?"table":"cards",rowPerField:raw.rowPerField===true,idField:raw.idField,columns:Array.isArray(raw.columns)?raw.columns:undefined,columnLabels:raw.columnLabels&&typeof raw.columnLabels==="object"?raw.columnLabels:undefined};}
return{type:"cards"};}
function itemSource(item,category=activeCategory){const categoryData=itemsData[category];return item.Source||item.source||categoryData?.source||categoryData?.Source||"Core";}
function getItemName(item){return item.Name||"???";}
function renderAsCards(entries,subcat,q,rowEl){entries.forEach(obj=>{if(typeof obj!=="object"||!obj)return;const name=getItemName(obj);if(q&&!name.toLowerCase().includes(q)&&!Object.values(obj).some(v=>v&&v.toString().toLowerCase().includes(q)))return;const col=document.createElement("div");col.className=`col-12 col-md-${edgeColSize}`;const card=document.createElement("div");card.className="card h-100 bg-body border shadow-sm overflow-hidden rounded-3";const body=document.createElement("div");body.className="card-body bg-body-secondary";const source=itemSource(obj);body.insertAdjacentHTML("beforeend",`<h5 class="card-title">${escapeHTML(name)} <span class="badge bg-secondary">${escapeHTML(subcat)}</span> <span class="badge bg-info">${escapeHTML(source)}</span></h5>`);Object.entries(obj).forEach(([k,v])=>{if(["Name","Source","source"].includes(k))return;if(Array.isArray(v)&&v.length>0&&typeof v[0]==="object"){const meta=(itemsData[activeCategory]._display&&itemsData[activeCategory]._display[k])||{};const columns=meta.columns||Object.keys(v[0]);const wrap=document.createElement("div");wrap.className="table-responsive mt-2";const table=document.createElement("table");table.className="table table-sm table-striped mb-0";const thead=document.createElement("thead");const headRow=document.createElement("tr");columns.forEach(c=>{const th=document.createElement("th");th.textContent=c;headRow.appendChild(th);});thead.appendChild(headRow);table.appendChild(thead);const tbody=document.createElement("tbody");v.forEach(entry=>{const tr=document.createElement("tr");columns.forEach(c=>{const td=document.createElement("td");const val=entry[c];td.textContent=val==null?"—":String(val);tr.appendChild(td);});tbody.appendChild(tr);});table.appendChild(tbody);wrap.appendChild(table);const label=document.createElement("p");label.innerHTML=`<strong>${escapeHTML(k)}:</strong>`;body.appendChild(label);body.appendChild(wrap);return;}
let displayValue=String(v);if(k==="Price"&&!isNaN(v)){displayValue=`₽${v}`;}
body.insertAdjacentHTML("beforeend",`<p><strong>${escapeHTML(k)}:</strong> ${escapeHTML(displayValue)}</p>`);});card.appendChild(body);col.appendChild(card);rowEl.appendChild(col);});}
function renderAsTable(entries,subcat,meta,q,rowEl){const filtered=entries.filter(obj=>{if(!q)return true;const hay=Object.values(obj).map(v=>(v==null?"":String(v).toLowerCase())).join(" ");return hay.includes(q);});if(filtered.length===0)return;const col=document.createElement("div");col.className="col-12";const card=document.createElement("div");card.className="card h-100 bg-body border shadow-sm overflow-hidden rounded-3";const body=document.createElement("div");body.className="card-body bg-body-secondary";const wrap=document.createElement("div");wrap.className="table-responsive";const table=document.createElement("table");table.className="table table-sm table-striped mb-0 items-table";if(meta.rowPerField)table.classList.add("items-table--transposed");if(!meta.rowPerField){let cols;if(meta.columns){cols=meta.columns.filter(k=>filtered.some(e=>Object.prototype.hasOwnProperty.call(e,k)));const union=new Set();filtered.forEach(e=>Object.keys(e).forEach(k=>union.add(k)));[...union].forEach(k=>{if(!cols.includes(k))cols.push(k);});}else{const union=new Set();filtered.forEach(e=>Object.keys(e).forEach(k=>union.add(k)));cols=[...union];}
if(Array.isArray(meta.columnWidths)&&meta.columnWidths.length){const cg=document.createElement("colgroup");cols.forEach((_,i)=>{const c=document.createElement("col");const w=meta.columnWidths[i]||meta.columnWidths[meta.columnWidths.length-1];if(w)c.style.width=w;cg.appendChild(c);});table.appendChild(cg);}
const thead=document.createElement("thead");const headRow=document.createElement("tr");cols.forEach(k=>{const th=document.createElement("th");const label=(meta.columnLabels&&meta.columnLabels[k])||k;th.textContent=label;headRow.appendChild(th);});thead.appendChild(headRow);table.appendChild(thead);const tbody=document.createElement("tbody");filtered.forEach(obj=>{const tr=document.createElement("tr");cols.forEach(k=>{const td=document.createElement("td");const v=obj[k];td.innerHTML=v==null?"—":escapeHTML(String(v));tr.appendChild(td);});tbody.appendChild(tr);});table.appendChild(tbody);wrap.appendChild(table);body.appendChild(wrap);card.appendChild(body);col.appendChild(card);rowEl.appendChild(col);return;}
const idField=resolveIdField(meta.idField,filtered);const rowKeysOrdered=collectRowKeys(filtered,idField);const thead=document.createElement("thead");const headRow=document.createElement("tr");const cg=document.createElement("colgroup");const colLabel=document.createElement("col");colLabel.style.width="18ch";cg.appendChild(colLabel);filtered.forEach(()=>{const c=document.createElement("col");cg.appendChild(c);});table.appendChild(cg);headRow.appendChild(document.createElement("th"));filtered.forEach((obj,idx)=>{const hdr=document.createElement("th");const label=idField&&obj[idField]!=null?String(obj[idField]):`#${idx + 1}`;hdr.textContent=label;headRow.appendChild(hdr);});thead.appendChild(headRow);table.appendChild(thead);const tbody=document.createElement("tbody");rowKeysOrdered.forEach(k=>{const tr=document.createElement("tr");const th=document.createElement("th");th.textContent=k;tr.appendChild(th);filtered.forEach(obj=>{const td=document.createElement("td");const val=obj[k];td.innerHTML=val==null?"—":escapeHTML(String(val));tr.appendChild(td);});tbody.appendChild(tr);});table.appendChild(tbody);wrap.appendChild(table);body.appendChild(wrap);card.appendChild(body);col.appendChild(card);rowEl.appendChild(col);}
function resolveIdField(preferred,entries){if(preferred&&entries.some(e=>preferred in e))return preferred;const keyCounts={};entries.forEach(e=>{Object.keys(e).forEach(k=>{keyCounts[k]=keyCounts[k]||new Set();keyCounts[k].add(e[k]);});});let best=null;let maxDistinct=0;for(const[k,set]of Object.entries(keyCounts)){if(set.size>maxDistinct){best=k;maxDistinct=set.size;}}
return best;}
function collectRowKeys(entries,idField){const seen=new Set();const out=[];const push=k=>{if(!seen.has(k)){seen.add(k);out.push(k);}};entries.forEach(e=>{Object.keys(e).forEach(k=>{if(k===idField)return;push(k);});});return out;}
function escapeHTML(str){return str.replaceAll("&","&amp;").replaceAll("<","&lt;").replaceAll(">","&gt;").replaceAll('"',"&quot;").replaceAll("'","&#039;").replaceAll(/\n/g,"<br>");}